  FILTER NOT EXISTS { ?thr orkgp:P68005 ?cont . }
  FILTER NOT EXISTS { ?thr orkgp:P97000 ?desc . }
  FILTER NOT EXISTS { ?thr orkgp:P97001 ?theo . }
  ?mentioned rdfs:label ?mentionedLabel .
}
ORDER BY ?mentionedLabel
